using System.Threading; using System.Threading.Tasks; using System.Collections.Generic; using waabe_navi_mcp_server.Contracts; namespace waabe_navi_mcp_server.Services.Backends { public sealed partial class FallbackBackend { public async Task<TimelinerReportDto> GetTimelinerTasksAsync(CancellationToken ct) { return await UiThread.InvokeAsync(() => { var doc = Autodesk.Navisworks.Api.Application.MainDocument; var tl = Autodesk.Navisworks.Api.Timeliner.TimelinerDocumentExtensions.GetTimeliner(doc); var r = new TimelinerReportDto { success = true }; if (tl == null) { r.message = "none"; return r; } r.total_tasks = (int)tl.TaskTotalTasks(); r.tasks = new List<TimelinerTaskDto>(); foreach (var item in tl.Tasks) { if (item is Autodesk.Navisworks.Api.Timeliner.TimelinerTask t) r.tasks.Add(new TimelinerTaskDto { display_name = t.DisplayName ?? "", display_id = t.DisplayId ?? "", task_status = t.TaskStatus.ToString(), planned_start = t.PlannedStartDate?.ToString("yyyy-MM-dd") ?? "", planned_end = t.PlannedEndDate?.ToString("yyyy-MM-dd") ?? "", actual_start = t.ActualStartDate?.ToString("yyyy-MM-dd") ?? "", actual_end = t.ActualEndDate?.ToString("yyyy-MM-dd") ?? "", progress_percent = t.ProgressPercent, is_group = t.IsGroup, children_count = t.Children?.Count ?? 0 }); } r.message = r.total_tasks + " tasks"; return r; }); } } }